#!/usr/bin/env bash

set -euo pipefail

# =============================================================================
# AWS Deployment Script
# Supports both local development and CI/CD environments
# =============================================================================

# Color codes for output
readonly RED='\033[0;31m'
readonly GREEN='\033[0;32m'
readonly YELLOW='\033[1;33m'
readonly BLUE='\033[0;34m'
readonly NC='\033[0m' # No Color

# Default configuration
readonly SCRIPT_NAME="$(basename "$0")"
readonly TIMESTAMP="$(date +%Y%m%d%H%M%S)"
readonly LOG_FILE="/tmp/aws-deploy-${TIMESTAMP}.log"

# Deployment defaults
DEFAULT_REGION="us-east-1"
DEFAULT_ENVIRONMENT="staging"
DEFAULT_S3_BUCKET=""
DEFAULT_STACK_NAME=""
DEFAULT_ECR_REPO=""
DEFAULT_ECS_CLUSTER=""
DEFAULT_ECS_SERVICE=""
DEFAULT_LAMBDA_FUNCTION=""
DEPLOY_TYPE=""
DRY_RUN=false
FORCE=false
ROLLBACK_ON_FAILURE=true

# =============================================================================
# Logging Functions
# =============================================================================

log() {
    local level="$1"
    shift
    local message="$*"
    local timestamp
    timestamp="$(date '+%Y-%m-%d %H:%M:%S')"
    echo -e "${timestamp} [${level}] ${message}" | tee -a "${LOG_FILE}"
}

info() {
    log "INFO" "${GREEN}$*${NC}"
}

warn() {
    log "WARN" "${YELLOW}$*${NC}"
}

error() {
    log "ERROR" "${RED}$*${NC}"
}

debug() {
    if [[ "${VERBOSE:-false}" == "true" ]]; then
        log "DEBUG" "${BLUE}$*${NC}"
    fi
}

# =============================================================================
# Usage and Help
# =============================================================================

usage() {
    cat <<EOF
Usage: ${SCRIPT_NAME} [OPTIONS]

AWS Deployment Script - Deploy applications to AWS services

OPTIONS:
    -t, --type TYPE           Deployment type: s3, cloudformation, ecs, lambda, eb (required)
    -e, --environment ENV     Target environment: dev, staging, production (default: ${DEFAULT_ENVIRONMENT})
    -r, --region REGION       AWS region (default: ${DEFAULT_REGION})
    -p, --profile PROFILE     AWS CLI profile name (for local development)
    -b, --bucket BUCKET       S3 bucket name (for s3 deployment)
    -s, --stack STACK         CloudFormation stack name
    -c, --cluster CLUSTER     ECS cluster name
    --service SERVICE         ECS service name
    --ecr-repo REPO           ECR repository name
    --lambda-function FUNC    Lambda function name
    --template FILE           CloudFormation template file
    --source-dir DIR          Source directory to deploy (default: ./dist)
    --docker-file FILE        Dockerfile path (default: ./Dockerfile)
    --dry-run                 Simulate deployment without making changes
    --force                   Skip confirmation prompts
    --no-rollback             Disable automatic rollback on failure
    -v, --verbose             Enable verbose output
    -h, --help                Show this help message

ENVIRONMENT VARIABLES:
    AWS_ACCESS_KEY_ID         AWS access key (CI/CD)
    AWS_SECRET_ACCESS_KEY     AWS secret key (CI/CD)
    AWS_SESSION_TOKEN         AWS session token (optional, for assumed roles)
    AWS_DEFAULT_REGION        Default AWS region
    AWS_PROFILE               AWS CLI profile name
    DEPLOY_ENVIRONMENT        Target environment
    CI                        Set to 'true' in CI/CD environments

EXAMPLES:
    # Deploy static site to S3
    ${SCRIPT_NAME} -t s3 -b my-website-bucket -e production --source-dir ./build

    # Deploy CloudFormation stack
    ${SCRIPT_NAME} -t cloudformation -s my-stack --template template.yaml -e staging

    # Deploy to ECS
    ${SCRIPT_NAME} -t ecs -c my-cluster --service my-service --ecr-repo my-app -e production

    # Deploy Lambda function
    ${SCRIPT_NAME} -t lambda --lambda-function my-function --source-dir ./dist

    # Dry run
    ${SCRIPT_NAME} -t s3 -b my-bucket --dry-run
EOF
    exit 0
}

# =============================================================================
# Utility Functions
# =============================================================================

cleanup() {
    local exit_code=$?
    if [[ ${exit_code} -ne 0 ]]; then
        error "Deployment failed with exit code ${exit_code}"
        error "Check log file: ${LOG_FILE}"
        if [[ "${ROLLBACK_ON_FAILURE}" == "true" && "${DRY_RUN}" == "false" ]]; then
            warn "Attempting rollback..."
            perform_rollback || error "Rollback failed!"
        fi
    fi
    # Clean up temporary files
    rm -f /tmp/aws-deploy-payload-*.zip 2>/dev/null || true
    exit ${exit_code}
}

trap cleanup EXIT
trap 'error "Script interrupted"; exit 130' INT TERM

confirm_action() {
    local message="$1"
    if [[ "${FORCE}" == "true" ]] || [[ "${CI:-false}" == "true" ]]; then
        return 0
    fi
    echo -e "${YELLOW}${message}${NC}"
    read -rp "Continue? (y/N): " response
    case "${response}" in
        [yY][eE][sS]|[yY]) return 0 ;;
        *) error "Deployment cancelled by user"; exit 1 ;;
    esac
}

check_command() {
    local cmd="$1"
    if ! command -v "${cmd}" &>/dev/null; then
        error "Required command '${cmd}' not found. Please install it."
        exit 1
    fi
}

validate_environment() {
    local env="$1"
    case "${env}" in
        dev|development|staging|production|prod) return 0 ;;
        *)
            error "Invalid environment: ${env}. Must be one of: dev, staging, production"
            exit 1
            ;;
    esac
}

mask_secret() {
    local value="$1"
    local visible_chars=4
    if [[ ${#value} -le ${visible_chars} ]]; then
        echo "****"
    else
        echo "${value:0:${visible_chars}}$(printf '*%.0s' $(seq 1 $((${#value} - visible_chars))))"
    fi
}

# =============================================================================
# AWS Authentication
# =============================================================================

configure_aws_auth() {
    info "Configuring AWS authentication..."

    # Check if running in CI/CD environment
    if [[ "${CI:-false}" == "true" ]]; then
        info "CI/CD environment detected"
        configure_ci_auth
    else
        info "Local development environment detected"
        configure_local_auth
    fi

    # Validate authentication
    validate_aws_auth
}

configure_ci_auth() {
    # In CI/CD, expect environment variables or IAM role
    if [[ -n "${AWS_ACCESS_KEY_ID:-}" && -n "${AWS_SECRET_ACCESS_KEY:-}" ]]; then
        info "Using AWS access key credentials"
        debug "Access Key ID: $(mask_secret "${AWS_ACCESS_KEY_ID}")"

        export AWS_ACCESS_KEY_ID
        export AWS_SECRET_ACCESS_KEY

        if [[ -n "${AWS_SESSION_TOKEN:-}" ]]; then
            info "Session token detected (assumed role)"
            export AWS_SESSION_TOKEN
        fi
    elif [[ -n "${AWS_ROLE_ARN:-}" ]]; then
        info "Assuming IAM role: ${AWS_ROLE_ARN}"
        assume_role "${AWS_ROLE_ARN}"
    elif curl -s --connect-timeout 2 http://169.254.169.254/latest/meta-data/iam/security-credentials/ &>/dev/null; then
        info "Using EC2 instance profile / ECS task role"
    elif [[ -n "${AWS_WEB_IDENTITY_TOKEN_FILE:-}" ]]; then
        info "Using web identity token (EKS/OIDC)"
    else
        error "No AWS credentials found in CI/CD environment"
        error "Set AWS_ACCESS_KEY_ID/AWS_SECRET_ACCESS_KEY or configure IAM role"
        exit 1
    fi

    # Set region
    export AWS_DEFAULT_REGION="${AWS_REGION:-${AWS_DEFAULT_REGION:-${DEFAULT_REGION}}}"
    info "AWS Region: ${AWS_DEFAULT_REGION}"
}

configure_local_auth() {
    if [[ -n "${AWS_PROFILE:-}" ]]; then
        info "Using AWS profile: ${AWS_PROFILE}"
        export AWS_PROFILE
    elif [[ -n "${PROFILE:-}" ]]; then
        info "Using AWS profile: ${PROFILE}"
        export AWS_PROFILE="${PROFILE}"
    fi

    # Check for SSO session
    if aws configure get sso_start_url --profile "${AWS_PROFILE:-default}" &>/dev/null; then
        info "SSO profile detected, checking session..."
        if ! aws sts get-caller-identity --profile "${AWS_PROFILE:-default}" &>/dev/null; then
            warn "SSO session expired, initiating login..."
            aws sso login --profile "${AWS_PROFILE:-default}"
        fi
    fi

    # Set region from profile or default
    local profile_region
    profile_region="$(aws configure get region --profile "${AWS_PROFILE:-default}" 2>/dev/null || echo "")"
    export AWS_DEFAULT_REGION="${AWS_REGION:-${profile_region:-${DEFAULT_REGION}}}"
    info "AWS Region: ${AWS_DEFAULT_REGION}"
}

assume_role() {
    local role_arn="$1"
    local session_name="${AWS_ROLE_SESSION_NAME:-deploy-session-${TIMESTAMP}}"

    info "Assuming role: ${role_arn}"

    local credentials
    credentials=$(aws sts assume-role \
        --role-arn "${role_arn}" \
        --role-session-name "${session_name}" \
        --duration-seconds 3600 \
        --output json 2>&1) || {
        error "Failed to assume role: ${role_arn}"
        error "${credentials}"
        exit 1
    }

    export AWS_ACCESS_KEY_ID
    export AWS_SECRET_ACCESS_KEY
    export AWS_SESSION_TOKEN
    AWS_ACCESS_KEY_ID="$(echo "${credentials}" | jq -r '.Credentials.AccessKeyId')"
    AWS_SECRET_ACCESS_KEY="$(echo "${credentials}" | jq -r '.Credentials.SecretAccessKey')"
    AWS_SESSION_TOKEN="$(echo "${credentials}" | jq -r '.Credentials.SessionToken')"

    info "Successfully assumed role"
}

validate_aws_auth() {
    info "Validating AWS credentials..."

    local identity
    identity=$(aws sts get-caller-identity --output json 2>&1) || {
        error "AWS authentication failed!"
        error "${identity}"
        error "Please check your credentials and try again."
        exit 1
    }

    local account_id arn
    account_id="$(echo "${identity}" | jq -r '.Account')"
    arn="$(echo "${identity}" | jq -r '.Arn')"

    info "Authenticated as: ${arn}"
    info "AWS Account: ${account_id}"

    # Safety check for production deployments
    if [[ "${ENVIRONMENT}" == "production" || "${ENVIRONMENT}" == "prod" ]]; then
        if [[ -n "${PRODUCTION_ACCOUNT_ID:-}" && "${account_id}" != "${PRODUCTION_ACCOUNT_ID}" ]]; then
            error "Account mismatch! Expected ${PRODUCTION_ACCOUNT_ID} for production, got ${account_id}"
            exit 1
        fi
        warn "⚠️  PRODUCTION DEPLOYMENT ⚠️"
        confirm_action "You are about to deploy to PRODUCTION (Account: ${account_id})"
    fi
}

# =============================================================================
