deploy_s3() {
    local bucket="${S3_BUCKET}"
    local source_dir="${SOURCE_DIR:-./dist}"

    info "Starting S3 deployment..."
    info "Bucket: ${bucket}"
    info "Source: ${source_dir}"
    info "Environment: ${ENVIRONMENT}"

    # Validate source directory
    if [[ ! -d "${source_dir}" ]]; then
        error "Source directory not found: ${source_dir}"
        exit 1
    fi

    # Check if bucket exists
    if ! aws s3api head-bucket --bucket "${bucket}" 2>/dev/null; then
        error "S3 bucket '${bucket}' does not exist or is not accessible"
        exit 1
    fi

    # Create backup tag
    local backup_prefix="backups/${TIMESTAMP}"
    info "Creating backup at s3://${bucket}/${backup_prefix}/"

    if [[ "${DRY_RUN}" == "false" ]]; then
        aws s3 sync "s3://${bucket}" "s3://${bucket}/${backup_prefix}" \
            --exclude "${backup_prefix}/*" \
            --quiet 2>&1 | tee -a "${LOG_FILE}" || warn "Backup creation had warnings"
    else
        info "[DRY RUN] Would backup s3://${bucket} to s3://${bucket}/${backup_prefix}/"
    fi

    # Sync files to S3
    local sync_args=(
        "${source_dir}/" "s3://${bucket}/"
        --delete
        --exclude ".git/*"
        --exclude ".env*"
        --exclude "*.map"
        --exclude "${backup_prefix}/*"
    )

    # Add cache control headers for common file types
    if [[ "${DRY_RUN}" == "true" ]]; then
        sync_args+=(--dryrun)
    fi

    info "Syncing files to S3..."
    aws s3 sync "${sync_args[@]}" 2>&1 | tee -a "${LOG_FILE}"

    # Set cache headers for different file types
    if [[ "${DRY_RUN}" == "false" ]]; then
        info "Setting cache control headers..."

        # HTML files - no cache
        aws s3 cp "s3://${bucket}/" "s3://${bucket}/" \
            --recursive \
            --exclude "*" \
            --include "*.html" \
            --cache-control "no-cache, no-store, must-revalidate" \
            --content-type "text/html" \
            --metadata-directive REPLACE \
            --quiet 2>&1 | tee -a "${LOG_FILE}" || true

        # Static assets - long cache
        aws s3 cp "s3://${bucket}/" "s3://${bucket}/" \
            --recursive \
            --exclude "*" \
            --include "*.js" \
            --include "*.css" \
            --include "*.png" \
            --include "*.jpg" \
            --include "*.gif" \
            --include "*.svg" \
            --include "*.woff2" \
            --cache-control "public, max-age=31536000, immutable" \
            --metadata-directive REPLACE \
            --quiet 2>&1 | tee -a "${LOG_FILE}" || true
    fi

    # Invalidate CloudFront distribution if configured
    if [[ -n "${CLOUDFRONT_DISTRIBUTION_ID:-}" ]]; then
        info "Invalidating CloudFront distribution: ${CLOUDFRONT_DISTRIBUTION_ID}"
        if [[ "${DRY_RUN}" == "false" ]]; then
            local invalidation_id
            invalidation_id=$(aws cloudfront create-invalidation \
                --distribution-id "${CLOUDFRONT_DISTRIBUTION_ID}" \
                --paths "/*" \
                --query 'Invalidation.Id' \
                --output text 2>&1) || {
                warn "CloudFront invalidation failed: ${invalidation_id}"
            }
            info "CloudFront invalidation created: ${invalidation_id}"
        else
            info "[DRY RUN] Would invalidate CloudFront distribution